// Kiểm tra payload rỗng hoặc không phải object
if (!msg.payload || typeof msg.payload !== 'object') {
    node.warn('Dữ liệu không hợp lệ — bỏ qua: ' + JSON.stringify(msg.payload));
    return null;
}

// Gán metadata
msg.deviceId = msg.payload.device || 'unknown';
msg.timestamp = msg.payload.timestamp || Date.now();
msg.topic = msg._topic;

// Đánh dấu thời gian đến (ms)
msg.arrivalMs = Date.now();

// Thêm vào flow context để merge
var key = msg.topic.split('/').pop(); // env | soil | light | status
flow.set('last_' + key, msg.payload);
flow.set('last_' + key + '_ts', msg.arrivalMs);

return msg;

var p = msg.payload;
var warnings = [];
var alerts = [];

// --- Nhiệt độ (env) ---
if (p.temperature !== undefined) {
    if (p.temperature > 38) {
        alerts.push('Nhiệt độ QUÁ CAO: ' + p.temperature + '°C');
    } else if (p.temperature > 35) {
        warnings.push('Nhiệt độ cao: ' + p.temperature + '°C');
    } else if (p.temperature < 10) {
        warnings.push('Nhiệt độ THẤP: ' + p.temperature + '°C');
    }
}

// --- Độ ẩm không khí (env) ---
if (p.humidity !== undefined) {
    if (p.humidity > 90) {
        alerts.push('Độ ẩm KK QUÁ CAO: ' + p.humidity + '%');
    } else if (p.humidity > 80) {
        warnings.push('Độ ẩm KK cao: ' + p.humidity + '%');
    } else if (p.humidity < 30) {
        alerts.push('Độ ẩm KK THẤP: ' + p.humidity + '%');
    }
}

// --- Độ ẩm đất (soil) ---
if (p.moisture !== undefined) {
    if (p.moisture < 20) {
        alerts.push('Đất KHÔ hại: ' + p.moisture + '%');
    } else if (p.moisture < 30) {
        warnings.push('Đất khô cần tưới: ' + p.moisture + '%');
    } else if (p.moisture > 80) {
        warnings.push('Đất ÚNG nước: ' + p.moisture + '%');
    }
}

// --- Ánh sáng (light) ---
if (p.intensity !== undefined) {
    if (p.intensity < 10) {
        warnings.push('Ánh sáng yếu: ' + p.intensity + '%');
    }
}

// Gắn cờ cảnh báo vào msg
msg.warnings = warnings;
msg.alerts = alerts;
msg.hasWarning = warnings.length > 0;
msg.hasAlert = alerts.length > 0;

// Gửi cảnh báo → toast
if (alerts.length > 0) {
    var alertMsg = {
        payload: {
            topic: 'ALERT',
            text: alerts.join(' | '),
            type: 'error',
            timeout: 15000
        }
    };
    node.send([null, alertMsg]);
}

if (warnings.length > 0) {
    var warnMsg = {
        payload: {
            topic: 'WARN',
            text: warnings.join(' | '),
            type: 'warning',
            timeout: 8000
        }
    };
    node.send([null, null, warnMsg]);
}

return msg;

// Gom 4 sensor gần nhất thành 1 payload
var env  = flow.get('last_env')   || {};
var soil = flow.get('last_soil')  || {};
var light = flow.get('last_light') || {};
var status = flow.get('last_status') || {};

var now = Date.now();

var merged = {
    ts: now,
    temp:     env.temperature   !== undefined ? env.temperature  : null,
    humidity: env.humidity      !== undefined ? env.humidity     : null,
    soil:     soil.moisture    !== undefined ? soil.moisture   : null,
    light:    light.intensity  !== undefined ? light.intensity  : null,
    pump:     status.pump       !== undefined ? status.pump      : null,
    fan:      status.fan        !== undefined ? status.fan       : null,
    mode:     status.mode       || 'unknown'
};

// Gửi riêng từng msg cho chart
var out = [];

if (merged.temp !== null) {
    out.push({ payload: merged.temp, topic: 'temp', deviceId: env.device, ts: now });
}
if (merged.humidity !== null) {
    out.push({ payload: merged.humidity, topic: 'humidity', deviceId: env.device, ts: now });
}
if (merged.soil !== null) {
    out.push({ payload: merged.soil, topic: 'soil', deviceId: env.device, ts: now });
}
if (merged.light !== null) {
    out.push({ payload: merged.light, topic: 'light', deviceId: env.device, ts: now });
}

return [out, { payload: merged }];

var p = msg.payload;
// Giới hạn giá trị hợp lý
var temp = parseFloat(p.temperature);
var hum  = parseFloat(p.humidity);

if (isNaN(temp) || temp < -10 || temp > 80) {
    node.warn('Nhiệt độ không hợp lệ: ' + temp); return null;
}
if (isNaN(hum) || hum < 0 || hum > 100) {
    node.warn('Độ ẩm không hợp lệ: ' + hum); return null;
}

msg.payload = {
    temperature: Math.round(temp * 10) / 10,
    humidity:    Math.round(hum  * 10) / 10,
    device:      p.device || 'unknown',
    timestamp:   p.timestamp || Date.now()
};

// Gửi 2 msg: temp → gauge/chart, hum → gauge/chart
return [
    { payload: msg.payload.temperature, topic: 'temperature', deviceId: msg.payload.device, ts: msg.payload.timestamp },
    { payload: msg.payload.humidity,    topic: 'humidity',    deviceId: msg.payload.device, ts: msg.payload.timestamp }
];

var p = msg.payload;
var moisture = parseFloat(p.moisture);

if (isNaN(moisture) || moisture < 0 || moisture > 100) {
    node.warn('Độ ẩm đất không hợp lệ: ' + moisture); return null;
}

msg.payload = {
    moisture: Math.round(moisture * 10) / 10,
    device:   p.device || 'unknown',
    timestamp: p.timestamp || Date.now()
};

return { payload: msg.payload.moisture, topic: 'moisture', deviceId: msg.payload.device, ts: msg.payload.timestamp };

var p = msg.payload;
var intensity = parseFloat(p.intensity);

if (isNaN(intensity) || intensity < 0 || intensity > 100) {
    node.warn('Ánh sáng không hợp lệ: ' + intensity); return null;
}

msg.payload = {
    intensity: Math.round(intensity * 10) / 10,
    device:     p.device || 'unknown',
    timestamp:  p.timestamp || Date.now()
};

return { payload: msg.payload.intensity, topic: 'light', deviceId: msg.payload.device, ts: msg.payload.timestamp };

var p = msg.payload;

// Lưu trạng thái device ra context để dùng chung
flow.set('dev_pump',   !!p.pump);
flow.set('dev_fan',    !!p.fan);
flow.set('dev_mode',   p.mode || 'unknown');
flow.set('dev_rssi',   p.rssi);
flow.set('dev_uptime', p.uptime);

return {
    payload: {
        pump:   !!p.pump,
        fan:    !!p.fan,
        mode:   p.mode  || 'unknown',
        rssi:   p.rssi  || 0,
        uptime: p.uptime || 0,
        device: p.device || 'unknown'
    }
};

var p = msg.payload;

// pump indicator
var pumpLabel = p.pump ? 'ON' : 'OFF';
var pumpColor = p.pump ? '#00b050' : '#999';

// fan indicator  
var fanLabel = p.fan ? 'ON' : 'OFF';
var fanColor = p.fan ? '#00b050' : '#999';

// mode
var modeText = (p.mode || 'unknown').toString();

// rssi → mức wifi
var rssi = p.rssi || 0;
var rssiLevel = rssi > -50 ? 'Tốt' : rssi > -70 ? 'Khá' : 'Yếu';

return [
    {
        payload: pumpLabel,
        topic: 'pump_on_off',
        color: pumpColor
    },
    {
        payload: fanLabel,
        topic: 'fan_on_off',
        color: fanColor
    },
    {
        payload: modeText,
        topic: 'mode'
    },
    {
        payload: rssi + ' dBm (' + rssiLevel + ')',
        topic: 'rssi'
    }
];

var p = msg.payload;

// ESP32 gửi: { reasons: [...], buzzer: true/false }
var reasons = p.reasons || [];
var buzzer  = p.buzzer;

var text = reasons.length > 0
    ? 'CẢNH BÁO: ' + reasons.join(' | ')
    : 'Cảnh báo không xác định';

return {
    payload: {
        topic: 'ALERT',
        text: text,
        type: buzzer ? 'error' : 'warning',
        timeout: 15000
    }
};

// Đồng bộ giao diện với payload iot/farm/status (pump, fan, mode)
var p = msg.payload;
if (!p || typeof p !== 'object') {
    return [null, null, null];
}

var modeStr = (p.mode || 'manual').toString().toLowerCase();
var isAuto = (modeStr === 'auto');

flow.set('dev_pump', !!p.pump);
flow.set('dev_fan', !!p.fan);
flow.set('dev_mode', isAuto ? 'auto' : 'manual');

// payload boolean + topic khớp ui_switch — cập nhật vị trí công tắc, passthru:false không gửi lại MQTT
return [
    { payload: isAuto, topic: 'mode' },
    { payload: !!p.pump, topic: 'pump' },
    { payload: !!p.fan, topic: 'fan' }
];

// Gửi JSON đúng format ESP32: main.cpp đọc key mode, pump, fan, buzzer (không dùng cmd)
function asBool(v) {
    return v === true || v === 1 || v === '1' || v === 'true';
}

var topic = msg.topic || '';
var payload = msg.payload;

if (topic === 'mode') {
    var newMode = asBool(payload) ? 'auto' : 'manual';
    flow.set('dev_mode', newMode);
    node.log('Chế độ: ' + newMode);
    return { payload: { mode: newMode } };
}

if (topic === 'pump') {
    var on = asBool(payload);
    flow.set('dev_pump', on);
    return { payload: { pump: on } };
}

if (topic === 'fan') {
    var fon = asBool(payload);
    flow.set('dev_fan', fon);
    return { payload: { fan: fon } };
}

if (topic === 'buzzer') {
    return { payload: { buzzer: asBool(payload) } };
}

node.warn('Control: topic không xử lý được: ' + topic);
return null;
